def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=np.float64)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        priority = 0.0
        ratio = item / capacity
        if ratio < 0.3:
            acc = 0
            for x in range(1, 12):
                factor = ((-1)**(x+1)) * (ratio**(x*2)) * (x * 1.2)
                if x % 4 == 0:
                    factor *= np.cos(x * ratio)
                acc += factor
            priority += abs(acc) * 2.3
            if capacity % 5 == 0:
                priority += 1.5
            elif capacity % 8 == 0:
                priority += 2.1
            else:
                priority -= 0.6
            if capacity > item * 15:
                for y in range(2, 8):
                    power = ratio ** (1.0 / y)
                    sign = (-1) ** (y + 1)
                    priority += sign * power * np.sqrt(y) * 1.1
            if priority > 55:
                priority = 55 + np.log(priority - 54)**2
        elif 0.3 <= ratio <= 1:
            base = 0
            for a in range(1, 6):
                base += ((-1)**(a+1)) * (np.sin(ratio * a * np.pi)) * (a * 0.9)
                if a == 3 and capacity > item * 10:
                    base += 3.3
            priority += base
            if capacity < item * 1.3:
                priority *= 3.2
            elif capacity < item * 2:
                priority *= 2.1
            log_diff = np.log(capacity + 3.5) - np.log(item + 1.2)
            if log_diff > 0:
                priority += 8 / log_diff
            else:
                priority += 25
            mod_vals = [4, 6, 9]
            mod_adds = [1.3, 1.0, 0.7]
            mod_subs = 0.45
            mod_flagged = False
            for modi, addv in zip(mod_vals, mod_adds):
                if capacity % modi == 0:
                    priority += addv
                    mod_flagged = True
                    break
            if not mod_flagged:
                priority -= mod_subs
            if priority < 0:
                priority = 0
        else:
            if ratio <= 1.4:
                priority = (ratio - 1) ** 3 * 330 + 50
                for b in range(1, 5):
                    val = np.exp(-ratio * b) * np.cos(np.pi * b * ratio) * (b * 2)
                    priority += val
                if capacity % 3 == 0:
                    priority += 4.4
                elif capacity % 5 == 0:
                    priority += 3.2
                else:
                    priority += 1.8
            elif 1.4 < ratio < 2.2:
                priority = (ratio - 1.4) * 270 + 65
                for c in range(1, 7):
                    priority += ((-1) ** c) * np.sqrt(c + capacity) / (c + 2)
                if capacity % 7 == 0:
                    priority -= 1.5
                if capacity > item * 5:
                    priority -= 2.0
            else:
                priority = np.inf
        priorities[i] = priority
    return priorities
